arguments.prompt:
You are building a Blazor Web App for a logistics company that tracks shipments. The project has already been scaffolded at `/tmp/sv-25c10ebfe8e043a8b385cb8e7722e977/ShipmentTracker/` using `dotnet new blazor --interactivity Auto --auth Individual --all-interactive`. It uses .NET 11 preview, SQLite, ASP.NET Identity, and Interactive Auto render mode (prerender on server, then WebAssembly for client-side interactivity).

The solution has two projects:
- `ShipmentTracker` (server) — has `Data/ApplicationDbContext.cs`, `Data/ApplicationUser.cs`, `Program.cs`, `Components/`
- `ShipmentTracker.Client` (client WASM) — has `Pages/`, `Layout/`, `_Imports.razor`

## What to build

### 1. Shared DTOs in Client project (so both projects can use them)

Create `ShipmentTracker.Client/Models/ShipmentDto.cs`:
```csharp
namespace ShipmentTracker.Client.Models;

public class ShipmentDto
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public ShipmentStatus Status { get; set; }
    public DateTime ShippedDate { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public DateTime? ActualDelivery { get; set; }
    public string CustomerEmail { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

public enum ShipmentStatus
{
    Pending,
    PickedUp,
    InTransit,
    OutForDelivery,
    Delivered,
    Delayed,
    Returned
}
```

### 2. Server-side Shipment entity and DbContext

Create `ShipmentTracker/Data/Shipment.cs`:
```csharp
using System.ComponentModel.DataAnnotations;

namespace ShipmentTracker.Data;

public class Shipment
{
    public int Id { get; set; }

    [Required, MaxLength(20)]
    public string TrackingNumber { get; set; } = string.Empty;

    [Required, MaxLength(200)]
    public string Origin { get; set; } = string.Empty;

    [Required, MaxLength(200)]
    public string Destination { get; set; } = string.Empty;

    public int Status { get; set; }

    public DateTime ShippedDate { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public DateTime? ActualDelivery { get; set; }

    [Required, MaxLength(256)]
    public string CustomerEmail { get; set; } = string.Empty;

    [MaxLength(500)]
    public string Description { get; set; } = string.Empty;
}
```

Update `ApplicationDbContext.cs` to add:
```csharp
public DbSet<Shipment> Shipments => Set<Shipment>();
```

### 3. Shipment service interface in Client project

Create `ShipmentTracker.Client/Services/IShipmentService.cs`:
```csharp
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public interface IShipmentService
{
    Task<List<ShipmentDto>> GetAllShipmentsAsync();
    Task<ShipmentDto?> GetByTrackingNumberAsync(string trackingNumber);
    Task<List<ShipmentDto>> GetShipmentsForCustomerAsync(string email);
    Task<ShipmentDto> UpdateShipmentStatusAsync(int id, ShipmentStatus status);
}
```

### 4. Client-side implementation using HttpClient

Create `ShipmentTracker.Client/Services/ClientShipmentService.cs`:
```csharp
using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ClientShipmentService(HttpClient http) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetAllShipmentsAsync()
        => await http.GetFromJsonAsync<List<ShipmentDto>>("api/shipments") ?? [];

    public async Task<ShipmentDto?> GetByTrackingNumberAsync(string trackingNumber)
    {
        var response = await http.GetAsync($"api/shipments/track/{trackingNumber}");
        if (!response.IsSuccessStatusCode) return null;
        return await response.Content.ReadFromJsonAsync<ShipmentDto>();
    }

    public async Task<List<ShipmentDto>> GetShipmentsForCustomerAsync(string email)
        => await http.GetFromJsonAsync<List<ShipmentDto>>($"api/shipments/customer/{Uri.EscapeDataString(email)}") ?? [];

    public async Task<ShipmentDto> UpdateShipmentStatusAsync(int id, ShipmentStatus status)
    {
        var response = await http.PutAsJsonAsync($"api/shipments/{id}/status", new { Status = (int)status });
        response.EnsureSuccessStatusCode();
        return (await response.Content.ReadFromJsonAsync<ShipmentDto>())!;
    }
}
```

Register in `ShipmentTracker.Client/Program.cs`:
```csharp
using Microsoft.AspNetCore.Components.WebAssembly.Hosting;
using ShipmentTracker.Client.Services;

var builder = WebAssemblyHostBuilder.CreateDefault(args);

builder.Services.AddAuthorizationCore();
builder.Services.AddCascadingAuthenticationState();
builder.Services.AddAuthenticationStateDeserialization();

builder.Services.AddScoped(sp => new HttpClient { BaseAddress = new Uri(builder.HostEnvironment.BaseAddress) });
builder.Services.AddScoped<IShipmentService, ClientShipmentService>();

await builder.Build().RunAsync();
```

### 5. Server-side implementation of IShipmentService

Create `ShipmentTracker/Services/ServerShipmentService.cs`:
```csharp
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ServerShipmentService(ApplicationDbContext db) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetAllShipmentsAsync()
        => await db.Shipments.Select(s => MapToDto(s)).ToListAsync();

    public async Task<ShipmentDto?> GetByTrackingNumberAsync(string trackingNumber)
    {
        var s = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        return s is null ? null : MapToDto(s);
    }

    public async Task<List<ShipmentDto>> GetShipmentsForCustomerAsync(string email)
        => await db.Shipments.Where(s => s.CustomerEmail == email).Select(s => MapToDto(s)).ToListAsync();

    public async Task<ShipmentDto> UpdateShipmentStatusAsync(int id, ShipmentStatus status)
    {
        var s = await db.Shipments.FindAsync(id) ?? throw new KeyNotFoundException($"Shipment {id} not found");
        s.Status = (int)status;
        if (status == ShipmentStatus.Delivered)
            s.ActualDelivery = DateTime.UtcNow;
        await db.SaveChangesAsync();
        return MapToDto(s);
    }

    private static ShipmentDto MapToDto(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = (ShipmentStatus)s.Status,
        ShippedDate = s.ShippedDate,
        EstimatedDelivery = s.EstimatedDelivery,
        ActualDelivery = s.ActualDelivery,
        CustomerEmail = s.CustomerEmail,
        Description = s.Description
    };
}
```

Register in server `Program.cs` — add before `var app = builder.Build();`:
```csharp
builder.Services.AddScoped<IShipmentService, ServerShipmentService>();
```
Add the needed `using` statements at the top of Program.cs:
```csharp
using ShipmentTracker.Client.Services;
using ShipmentTracker.Services;
```

### 6. API Endpoints

Add API endpoints in server `Program.cs` AFTER `app.MapAdditionalIdentityEndpoints();` and BEFORE `app.Run();`:

```csharp
// Shipment API endpoints
var shipments = app.MapGroup("api/shipments").RequireAuthorization();

shipments.MapGet("/", async (IShipmentService svc) => await svc.GetAllShipmentsAsync());

shipments.MapGet("/track/{trackingNumber}", async (string trackingNumber, IShipmentService svc) =>
{
