### 5. Server-side implementation of IShipmentService

Create `ShipmentTracker/Services/ServerShipmentService.cs`:
```csharp
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ServerShipmentService(ApplicationDbContext db) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetAllShipmentsAsync()
        => await db.Shipments.Select(s => MapToDto(s)).ToListAsync();

    public async Task<ShipmentDto?> GetByTrackingNumberAsync(string trackingNumber)
    {
        var s = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        return s is null ? null : MapToDto(s);
    }

    public async Task<List<ShipmentDto>> GetShipmentsForCustomerAsync(string email)
        => await db.Shipments.Where(s => s.CustomerEmail == email).Select(s => MapToDto(s)).ToListAsync();

    public async Task<ShipmentDto> UpdateShipmentStatusAsync(int id, ShipmentStatus status)
    {
        var s = await db.Shipments.FindAsync(id) ?? throw new KeyNotFoundException($"Shipment {id} not found");
        s.Status = (int)status;
        if (status == ShipmentStatus.Delivered)
            s.ActualDelivery = DateTime.UtcNow;
        await db.SaveChangesAsync();
        return MapToDto(s);
    }

    private static ShipmentDto MapToDto(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = (ShipmentStatus)s.Status,
        ShippedDate = s.ShippedDate,
        EstimatedDelivery = s.EstimatedDelivery,
        ActualDelivery = s.ActualDelivery,
        CustomerEmail = s.CustomerEmail,
        Description = s.Description
    };
}
