using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ClientShipmentService(HttpClient http) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetAllShipmentsAsync()
        => await http.GetFromJsonAsync<List<ShipmentDto>>("api/shipments") ?? [];

    public async Task<ShipmentDto?> GetByTrackingNumberAsync(string trackingNumber)
    {
        var response = await http.GetAsync($"api/shipments/track/{trackingNumber}");
        if (!response.IsSuccessStatusCode) return null;
        return await response.Content.ReadFromJsonAsync<ShipmentDto>();
    }

    public async Task<List<ShipmentDto>> GetShipmentsForCustomerAsync(string email)
        => await http.GetFromJsonAsync<List<ShipmentDto>>($"api/shipments/customer/{Uri.EscapeDataString(email)}") ?? [];

    public async Task<ShipmentDto> UpdateShipmentStatusAsync(int id, ShipmentStatus status)
    {
        var response = await http.PutAsJsonAsync($"api/shipments/{id}/status", new { Status = (int)status });
        response.EnsureSuccessStatusCode();
        return (await response.Content.ReadFromJsonAsync<ShipmentDto>())!;
    }
}
