    private List<ShipmentDto>? shipments;
    private string filterText = "";
    private string statusFilter = "";
    private string? errorMessage;

    private IEnumerable<ShipmentDto> FilteredShipments =>
        (shipments ?? []).Where(s =>
            (string.IsNullOrEmpty(filterText) ||
             s.TrackingNumber.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
             s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase)) &&
            (string.IsNullOrEmpty(statusFilter) ||
             s.Status.ToString() == statusFilter));

    protected override async Task OnInitializedAsync() => await LoadShipments();

    private async Task LoadShipments()
    {
        try
        {
            errorMessage = null;
            shipments = await ShipmentService.GetAllShipmentsAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load shipments: {ex.Message}";
        }
    }

    private async Task UpdateStatus(ShipmentDto shipment, ChangeEventArgs e)
    {
        if (e.Value is string val && int.TryParse(val, out var statusInt))
        {
            try
            {
                errorMessage = null;
                var updated = await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, (ShipmentStatus)statusInt);
                var index = shipments!.FindIndex(s => s.Id == shipment.Id);
                if (index >= 0) shipments[index] = updated;
            }
            catch (Exception ex)
            {
                errorMessage = $"Failed to update status: {ex.Message}";
            }
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info text-dark",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Returned => "bg-dark",
        _ => "bg-secondary"
    };
}
