shipments.MapPut("/{id}/status", async (int id, StatusUpdateRequest request, IShipmentService svc) =>
{
    try
    {
        var result = await svc.UpdateShipmentStatusAsync(id, (ShipmentStatus)request.Status);
        return Results.Ok(result);
    }
    catch (KeyNotFoundException)
    {
        return Results.NotFound();
    }
});
