```razor
@page "/dispatcher"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<h2>📋 Dispatcher Dashboard</h2>

@if (errorMessage is not null)
{
    <div class="alert alert-danger">@errorMessage</div>
}

<div class="row mb-3">
    <div class="col-md-4">
        <input type="text" class="form-control" placeholder="Filter by tracking # or destination..."
               @bind="filterText" @bind:event="oninput" />
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="statusFilter">
            <option value="">All Statuses</option>
            @foreach (var s in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@s">@s</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button class="btn btn-outline-secondary" @onclick="LoadShipments">🔄 Refresh</button>
    </div>
</div>

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (!FilteredShipments.Any())
{
    <p>No shipments match your filters.</p>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Status</th>
                    <th>Shipped</th>
                    <th>Est. Delivery</th>
                    <th>Customer</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var s in FilteredShipments)
                {
                    <tr>
                        <td><strong>@s.TrackingNumber</strong></td>
                        <td>@s.Origin</td>
                        <td>@s.Destination</td>
                        <td>
                            <span class="badge @GetStatusBadgeClass(s.Status)">@s.Status</span>
                        </td>
                        <td>@s.ShippedDate.ToString("MMM dd, yyyy")</td>
                        <td>@(s.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "—")</td>
                        <td>@s.CustomerEmail</td>
                        <td>
                            @if (s.Status != ShipmentStatus.Delivered && s.Status != ShipmentStatus.Returned)
                            {
                                <select class="form-select form-select-sm d-inline-block w-auto"
                                        @onchange="e => UpdateStatus(s, e)">
                                    <option value="" selected disabled>Update…</option>
                                    @foreach (var status in Enum.GetValues<ShipmentStatus>())
                                    {
                                        @if (status != s.Status)
                                        {
                                            <option value="@((int)status)">@status</option>
                                        }
                                    }
                                </select>
                            }
                            else
                            {
                                <span class="text-muted">—</span>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private List<ShipmentDto>? shipments;
    private string filterText = "";
    private string statusFilter = "";
    private string? errorMessage;

    private IEnumerable<ShipmentDto> FilteredShipments =>
        (shipments ?? []).Where(s =>
            (string.IsNullOrEmpty(filterText) ||
             s.TrackingNumber.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
             s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase)) &&
            (string.IsNullOrEmpty(statusFilter) ||
             s.Status.ToString() == statusFilter));

    protected override async Task OnInitializedAsync() => await LoadShipments();

    private async Task LoadShipments()
    {
        try
        {
            errorMessage = null;
            shipments = await ShipmentService.GetAllShipmentsAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load shipments: {ex.Message}";
        }
    }

    private async Task UpdateStatus(ShipmentDto shipment, ChangeEventArgs e)
    {
        if (e.Value is string val && int.TryParse(val, out var statusInt))
        {
            try
            {
                errorMessage = null;
                var updated = await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, (ShipmentStatus)statusInt);
                var index = shipments!.FindIndex(s => s.Id == shipment.Id);
                if (index >= 0) shipments[index] = updated;
            }
            catch (Exception ex)
            {
                errorMessage = $"Failed to update status: {ex.Message}";
            }
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info text-dark",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Returned => "bg-dark",
        _ => "bg-secondary"
    };
}
```

